// --- PINCH TO ZOOM SUPPORT INSIDE IFRAME ---
let iframePinchDist = 0;
doc.addEventListener('touchstart', (e) => {
    if (e.touches.length === 2) {
        iframePinchDist = Math.hypot(
            e.touches[0].screenX - e.touches[1].screenX,
            e.touches[0].screenY - e.touches[1].screenY
        );
    }
}, { passive: false });

doc.addEventListener('touchmove', (e) => {
    if (e.touches.length === 2) {
        e.preventDefault();
        const dist = Math.hypot(
            e.touches[0].screenX - e.touches[1].screenX,
            e.touches[0].screenY - e.touches[1].screenY
        );
        if (iframePinchDist > 0) {
            const delta = dist / iframePinchDist;
            setScaleFactor(prev => Math.max(0.2, Math.min(prev * delta, 4.0)));
        }
        iframePinchDist = dist;
    }
}, { passive: false });

doc.addEventListener('touchend', () => { iframePinchDist = 0; });
doc.addEventListener('wheel', (e) => {
    if (e.ctrlKey) {
        e.preventDefault();
        const delta = e.deltaY > 0 ? 0.9 : 1.1;
        setScaleFactor(prev => Math.max(0.3, Math.min(prev * delta, 3.0)));
    }
}, { passive: false });

