// --- PINCH TO ZOOM SUPPORT INSIDE IFRAME ---
let iframePinchDist = 0;
doc.addEventListener('touchstart', (e) => {
    if (e.touches.length === 2) {
        iframePinchDist = Math.hypot(
            e.touches[0].screenX - e.touches[1].screenX,
            e.touches[0].screenY - e.touches[1].screenY
        );
    }
}, { passive: false });

doc.addEventListener('touchmove', (e) => {
    if (e.touches.length === 2) {
        e.preventDefault();
        const dist = Math.hypot(
            e.touches[0].screenX - e.touches[1].screenX,
            e.touches[0].screenY - e.touches[1].screenY
        );
        if (iframePinchDist > 0) {
            const delta = dist / iframePinchDist;
            const vp = viewportRef.current;
            const layer = doc.getElementById('book-layer') || document.getElementById('book-layer');

            if (vp && layer) {
                const minScale = window.innerWidth / 909;
                const currentScale = scaleRef.current;
                const newScale = Math.max(minScale, Math.min(currentScale * delta, 4.0));

                if (newScale !== currentScale) {
                    const docX = (e.touches[0].clientX + e.touches[1].clientX) / 2;
                    const docY = (e.touches[0].clientY + e.touches[1].clientY) / 2;

                    const Cx = (docX * currentScale) - vp.scrollLeft;
                    const Cy = (docY * currentScale) - vp.scrollTop;

                    scaleRef.current = newScale;
                    layer.style.transform = `scale(${newScale})`;
                    layer.style.height = `${contentDims.current.height * newScale}px`;

                    vp.scrollLeft = (docX * newScale) - Cx;
                    vp.scrollTop = (docY * newScale) - Cy;
                }
            }
        }
        iframePinchDist = dist;
    }
}, { passive: false });

