const onTouchMove = (e) => {
    if (e.touches.length === 2) {
        e.preventDefault();

        const tx1 = e.touches[0].screenX;
        const ty1 = e.touches[0].screenY;
        const tx2 = e.touches[1].screenX;
        const ty2 = e.touches[1].screenY;
        const cx1 = e.touches[0].clientX;
        const cy1 = e.touches[0].clientY;
        const cx2 = e.touches[1].clientX;
        const cy2 = e.touches[1].clientY;

        if (isParentPinching) return;
        isParentPinching = true;

        requestAnimationFrame(() => {
            const dist = Math.hypot(tx1 - tx2, ty1 - ty2);
            if (lastPinchDist.current > 0) {
                const delta = dist / lastPinchDist.current;
                const vp = viewportRef.current;
                const layer = document.getElementById('book-layer');

                if (vp && layer) {
                    const minScale = window.innerWidth / 909;
                    const currentScale = scaleRef.current;
                    const newScale = Math.max(minScale, Math.min(currentScale * delta, 4.0));

                    if (newScale !== currentScale) {
                        const rect = vp.getBoundingClientRect();
                        const pinchClientX = (cx1 + cx2) / 2;
                        const pinchClientY = (cy1 + cy2) / 2;

                        const Cx = pinchClientX - rect.left;
                        const Cy = pinchClientY - rect.top;

                        const docX = (Cx + vp.scrollLeft) / currentScale;
                        const docY = (Cy + vp.scrollTop) / currentScale;

                        scaleRef.current = newScale;
                        layer.style.transform = `scale(${newScale})`;
                        layer.style.height = `${bookHeight * newScale}px`;

                        vp.scrollLeft = (docX * newScale) - Cx;
                        vp.scrollTop = (docY * newScale) - Cy;
                    }
                }
            }
            lastPinchDist.current = dist;
            isParentPinching = false;
        });
    }
};

